class Solution:
    def getCoprimes(self, nums, edges):
        from math import gcd
        n = len(nums)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        coprime = [[] for _ in range(51)]
        for a in range(1, 51):
            for b in range(1, 51):
                if gcd(a, b) == 1:
                    coprime[a].append(b)
        last = [(-1, -1)] * 51
        ans = [-1] * n
        st = [(0, -1, 0, False)]
        saved = []
        while st:
            node, par, dep, processed = st.pop()
            if not processed:
                best = -1
                bd = -1
                for val in coprime[nums[node]]:
                    d, idx = last[val]
                    if d > bd:
                        bd = d
                        best = idx
                ans[node] = best
                v = nums[node]
                saved.append((v, last[v]))
                last[v] = (dep, node)
                st.append((node, par, dep, True))
                for nb in adj[node]:
                    if nb != par:
                        st.append((nb, node, dep + 1, False))
            else:
                v, prev = saved.pop()
                last[v] = prev
        return ans

