var getCoprimes = function(nums, edges) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const n = nums.length;
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); }
    const coprime = Array.from({length: 51}, () => []);
    for (let a = 1; a <= 50; a++) for (let b = 1; b <= 50; b++) if (gcd(a, b) === 1) coprime[a].push(b);
    const last = new Array(51).fill(null).map(() => [-1, -1]);
    const ans = new Array(n).fill(-1);
    const saved = {};
    const st = [[0, -1, 0, false]];
    while (st.length) {
        const frame = st.pop();
        const [node, par, dep, processed] = frame;
        if (!processed) {
            let best = -1, bd = -1;
            for (const val of coprime[nums[node]]) {
                const [d, idx] = last[val];
                if (d > bd) { bd = d; best = idx; }
            }
            ans[node] = best;
            saved[node + ',' + dep] = last[nums[node]];
            last[nums[node]] = [dep, node];
            st.push([node, par, dep, true]);
            for (const nb of adj[node]) if (nb !== par) st.push([nb, node, dep + 1, false]);
        } else {
            last[nums[node]] = saved[node + ',' + dep];
        }
    }
    return ans;
};
